import sys
from datetime import datetime

import boto3
from botocore.errorfactory import ClientError

sys.tracebacklimit = 0

ec2_client = boto3.client("ec2")


def validate_parameters(event, context):
    start_time = event["start_time"]
    end_time = event["end_time"]
    resource_id = event["resource_id"]
    timestamp_validation(start_time, end_time)
    resource_validation(resource_id)


def timestamp_validation(start_time, end_time):
    try:
        t1 = datetime.strptime(start_time, "%Y-%m-%dT%H:%M:%S")
        t2 = datetime.strptime(end_time, "%Y-%m-%dT%H:%M:%S")
        diff_minutes = (t2 - t1).total_seconds() / 60
        if diff_minutes > 0 and diff_minutes < 1:
            raise ValueError(
                f"[ERROR] The 'EndTime' ({t1}) should be at least 1 minute greater than 'StartTime' ({t2})"
            )
        elif diff_minutes <= 0:
            raise ValueError(f"[ERROR] The 'StartTime' ({t1}) should not be greater or equal than 'EndTime' ({t2})")
        else:
            print("[INFO] 'StartTime' and 'EndTime' timestamps are valid.")

    except Exception as e:
        raise ValueError(f"[ERROR] An error occurred when trying to validate the input parameters: {str(e)}") from None


def resource_validation(resource_id):
    try:
        if resource_id.startswith("vol-"):
            ec2_client.describe_volumes(VolumeIds=[resource_id])
        elif resource_id.startswith("i-"):
            ec2_client.describe_instances(InstanceIds=[resource_id])
        else:
            raise ValueError(f"[ERROR] The resource ID is not a valid EBS volume or EC2 instance: {resource_id}")

    except ClientError as error:
        raise ValueError(
            f"[ERROR] An error occurred when describing the target resource {resource_id} - {str(error)}"
        ) from None

    print(f"[INFO] Resource ID {resource_id} is valid.")

