from botocore.errorfactory import ClientError

INSTANCE_WIDGET_GROUP_SIZE = 6  # Number of volumes per instance-level widget group

# CloudWatch dashboard widget layout constants
# -- Common: used by both volume and instance dashboards --
WIDGET_FULL_WIDTH = 24  # Full dashboard width (24 columns)
WIDGET_HALF_WIDTH = 12  # Half width for side-by-side IOPS/Throughput graphs
WIDGET_GRAPH_HEIGHT = 9  # Height for IOPS/Throughput time-series graphs
WIDGET_EXCEEDED_HEIGHT = 6  # Height for ExceededCheck graphs
WIDGET_FOOTER_HEIGHT = 3  # Dashboard footer with delete instructions

# -- Volume widgets --
VOL_TEXT_HEADER_HEIGHT = 1  # Volume header text (e.g. "Volume: vol-xxx | Type: gp3")
VOL_DESC_HEIGHT = 8  # Volume metrics description and notes text

# -- Instance widgets --
INSTANCE_DESC_HEIGHT = 10  # Instance info, formulas, and notes text


# calculate period based on the start_time
def get_period_value(start_time):
    if (datetime.datetime.today() - start_time).days < 15:
        # Data points with a period of 60 seconds are available for 15 days
        period = 60
    elif (datetime.datetime.today() - start_time).days < 63:
        # 300 seconds are available for 63 days
        period = 300
    else:
        # 3600 seconds are available for 455 days
        period = 3600

    return period


# get all the attached volumes to an EC2
def get_attached_volumes(instance_id, ec2_client):
    try:
        describe_volumes_op = ec2_client.describe_volumes(
            Filters=[{"Name": "attachment.instance-id", "Values": [instance_id]}]
        )

        return [vol["VolumeId"] for vol in describe_volumes_op["Volumes"]]
    except ClientError as error:
        raise RuntimeError(
            f"[ERROR] An error occurred when trying to describe the volumes attached to the instance - {str(error)}."
        ) from None


# check if instance is Nitro-based using instance_type_info response
# Bare metal instances are built on the Nitro System:
# https://aws.amazon.com/jp/documentation-overview/ec2/
# Bare metal instances do not include a Hypervisor field in the
# describe_instance_types response, so we also check the BareMetal field.
def is_nitro_from_instance_type_info(instance_type_info):
    if instance_type_info.get("InstanceTypes"):
        instance_info = instance_type_info["InstanceTypes"][0]
        hypervisor = instance_info.get("Hypervisor", "")
        if hypervisor == "nitro":
            return True
        if instance_info.get("BareMetal", False) and hypervisor == "":
            return True
    return False


# check if instance is Nitro-based (standalone call when volume ID is the input)
def is_nitro_instance(instance_type, ec2_client):
    try:
        response = ec2_client.describe_instance_types(InstanceTypes=[instance_type])
        return is_nitro_from_instance_type_info(response)
    except ClientError as error:
        raise RuntimeError(
            f"[ERROR] An error occurred when trying to describe the instance type {instance_type} - {str(error)}"
        ) from None


# get volume IDs eligible for ExceededCheck metrics (non-magnetic, non-Multi-Attach)
def is_volume_exceeded_check_eligible(vol_info):
    if vol_info["vol_type"] == "standard":
        return False
    if vol_info["multi_attach"]:
        return False
    return True


# returns details for all volumes in a single DescribeVolumes call
def get_all_volume_details(vol_ids, ec2_client):
    try:
        response = ec2_client.describe_volumes(VolumeIds=vol_ids)
        results = {}
        for vol in response["Volumes"]:
            results[vol["VolumeId"]] = {
                "vol_size": vol["Size"],
                "vol_type": vol["VolumeType"],
                "attachments": vol.get("Attachments", []),
                "multi_attach": vol.get("MultiAttachEnabled", False),
            }
        return results
    except ClientError as error:
        raise RuntimeError(f"[ERROR] An error occurred when trying to describe the volumes {str(error)}.") from None


# calculates gp2 limits
def calculate_gp2_limits(vol_size):
    # Baseline performance of 3 IOPS/GB (minimum 100 IOPS) to a maximum of 16,000 IOPS
    baseline_iops = min(max(3 * vol_size, 100), 16000)

    # Throughput for volumes less than 170 will be maxed out at 128 mb/s else 250 mb/s
    max_burst_throughput = 128 if vol_size < 170 else 250
    baseline_throughput = min(baseline_iops / 4, max_burst_throughput)

    # check if burstable or not
    burstable_iops = 3000 if baseline_iops < 3000 else -1

    if burstable_iops < 0:
        return {"iops": baseline_iops, "throughput": baseline_throughput}
    else:
        return {
            "iops": baseline_iops,
            "max_iops": burstable_iops,
            "throughput": baseline_throughput,
            "max_throughput": max_burst_throughput,
        }


# calculates gp3 limits
def calculate_gp3_limits(volume_id, ec2_client):
    try:
        response = ec2_client.describe_volumes(VolumeIds=[volume_id])

        return {"iops": response["Volumes"][0]["Iops"], "throughput": response["Volumes"][0]["Throughput"]}
    except ClientError as error:
        raise RuntimeError(f"[ERROR] An error occurred when trying to describe the volume - {str(error)}.") from None


# calculates io1 and io2 limits
def calculate_io_limits(volume_id, ec2_client):
    try:
        response = ec2_client.describe_volumes(VolumeIds=[volume_id])

        iops = response["Volumes"][0]["Iops"]

        if iops <= 32000:
            return {"iops": iops, "throughput": min(iops / 4, 500)}
        else:
            return {"iops": iops, "throughput": min(iops / 64, 1000)}
    except ClientError as error:
        raise RuntimeError(f"[ERROR] An error occurred when trying to describe the volume - {str(error)}.") from None


# calculates st1 limits
def calculate_st1_limits(vol_size):
    # throughput
    burstable_throughput = round(min(vol_size * 250 / 1024, 500))
    baseline_throughput = round(min(vol_size * 40 / 1024, 500), 1)
    # Iops
    burstable_iops = burstable_throughput
    baseline_iops = baseline_throughput

    if baseline_throughput < 500:
        return {
            "iops": baseline_iops,
            "throughput": baseline_throughput,
            "max_iops": burstable_iops,
            "max_throughput": burstable_throughput,
        }
    else:
        return {"iops": baseline_iops, "throughput": baseline_throughput}


# calculates sc1 limits
def calculate_sc1_limits(vol_size):
    # throughput
    burstable_throughput = round(min(vol_size * 80 / 1024, 250))
    baseline_throughput = round(min(vol_size * 12 / 1024, 250), 1)
    # iops
    burstable_iops = burstable_throughput
    baseline_iops = baseline_throughput

    return {
        "iops": baseline_iops,
        "throughput": baseline_throughput,
        "max_iops": burstable_iops,
        "max_throughput": burstable_throughput,
    }


# calculates standard (magnetic) limits
def calculate_standard_limits():
    # Magnetic volumes: approximately 40-200 IOPS, 40-90 MB/s throughput
    return {"iops": 200, "throughput": 90}


# get the limits of EC2 instance
def get_ec2_info(instance_id, ec2_client):
    try:
        describe_instances_op = ec2_client.describe_instances(InstanceIds=[instance_id])
        instance_class = describe_instances_op["Reservations"][0]["Instances"][0]["InstanceType"]
        ebs_optimized = describe_instances_op["Reservations"][0]["Instances"][0]["EbsOptimized"]

        return {"instance_class": instance_class, "ebs_optimized": ebs_optimized}
    except ClientError as error:
        raise RuntimeError(f"[ERROR] An error occurred when trying to describe the instance - {str(error)}.") from None


def get_ec2_annotations(ec2_client, metric_type, ec2_info, instance_type_info=None):
    annotations = []

    if instance_type_info is None:
        try:
            instance_type_info = ec2_client.describe_instance_types(
                InstanceTypes=[ec2_info["instance_class"]],
            )
        except ClientError as error:
            raise RuntimeError(
                f"[ERROR] An error occurred when trying to describe the instance type "
                f"{ec2_info['instance_class']} - {str(error)}"
            ) from None

    if ec2_info["ebs_optimized"] and instance_type_info.get("InstanceTypes"):
        ebs_info = instance_type_info["InstanceTypes"][0].get("EbsInfo", {})
        ebs_optimized_info = ebs_info.get("EbsOptimizedInfo")
        if not ebs_optimized_info:
            return {"horizontal": annotations}
        baseline_iops = ebs_optimized_info["BaselineIops"]
        maximum_iops = ebs_optimized_info["MaximumIops"]
        baseline_throughput = ebs_optimized_info["BaselineThroughputInMBps"]
        maximum_throughput = ebs_optimized_info["MaximumThroughputInMBps"]

        if metric_type == "iops":
            # if baseline is same as maximum
            if baseline_iops == maximum_iops:
                annotations = [{"label": "Maximum IOPS", "value": maximum_iops}]
            else:
                annotations = [
                    {
                        "label": "Baseline IOPS",
                        "value": baseline_iops,
                    },
                    {"label": "Maximum IOPS", "value": maximum_iops},
                ]
        else:
            # if baseline is same as maximum
            if baseline_throughput == maximum_throughput:
                annotations = [{"label": "Maximum Throughput (Mib/s)", "value": maximum_throughput}]
            else:
                annotations = [
                    {
                        "label": "Baseline Throughput (Mib/s)",
                        "value": baseline_throughput,
                    },
                    {"label": "Maximum Throughput (Mib/s)", "value": maximum_throughput},
                ]

    return {"horizontal": annotations}


# generates volume annotations for throughput and iops
def get_volume_annotations(ec2_client, metric_type, vol_type, vol_id, vol_size):
    annotations = []
    if vol_type == "gp2":
        vol_limits = calculate_gp2_limits(vol_size)
    elif vol_type == "gp3":
        vol_limits = calculate_gp3_limits(vol_id, ec2_client)
    elif vol_type[:-1] == "io":
        vol_limits = calculate_io_limits(vol_id, ec2_client)
    elif vol_type == "st1":
        vol_limits = calculate_st1_limits(vol_size)
    elif vol_type == "sc1":
        vol_limits = calculate_sc1_limits(vol_size)
    elif vol_type == "standard":
        vol_limits = calculate_standard_limits()
    else:
        raise ValueError(f"[ERROR] Unsupported volume type: {vol_type}")

    if metric_type == "throughput":
        if vol_type in ["io1", "io2", "gp3"]:
            annotations = [
                {"label": "Baseline/Maximum Throughput (MB/s)", "value": vol_limits["throughput"]},
            ]
        else:
            if vol_limits.get("max_throughput"):
                annotations = [
                    {"label": "Baseline Throughput (MB/s)", "value": vol_limits["throughput"]},
                    {"label": "Maximum Throughput (MB/s)", "value": vol_limits["max_throughput"]},
                ]
            else:
                annotations = [{"label": "Baseline/Maximum Throughput (MB/s)", "value": vol_limits["throughput"]}]
    elif metric_type == "iops":
        if vol_type in ["io1", "io2", "gp3"]:
            annotations = [{"label": "Baseline/Maximum IOPS", "value": vol_limits["iops"]}]
        else:
            if vol_limits.get("max_iops"):
                annotations = [
                    {"label": "Baseline IOPS", "value": vol_limits["iops"]},
                    {"label": "Maximum IOPS", "value": vol_limits["max_iops"]},
                ]
            else:
                annotations = [{"label": "Baseline/Maximum IOPS", "value": vol_limits["iops"]}]

    return {"horizontal": annotations}


# creates volume level widgets per volume
def create_volume_widget(
    region,
    vol_id,
    vol_details,
    period,
    start_time,
    end_time,
    ec2_client,
    metric_counter=0,
    y_start=5,
    exceeded_check=False,
    instance_id="",
):
    metrics_req = [
        "VolumeIdleTime",
        "VolumeReadOps",
        "VolumeWriteOps",
        "VolumeReadBytes",
        "VolumeWriteBytes",
        "BurstBalance",
    ]
    is_burstable = True if vol_details["vol_type"] in ["gp2", "st1", "sc1"] else False

    if metric_counter == 0:
        metrics_numbrs = {metrics_req[i]: f"m{i + 1}" for i in range(len(metrics_req))}
        exprs = {"avg_iops": "e1", "avg_throughput": "e2"}
    else:
        metric_increment = (len(metrics_req) * metric_counter) + 1
        metrics_numbrs = {metrics_req[i]: f"m{i + metric_increment}" for i in range(len(metrics_req))}
        exprs_increment = 2 * metric_counter
        exprs = {"avg_iops": f"e{exprs_increment + 1}", "avg_throughput": f"e{exprs_increment + 2}"}

    throughput_annotations = get_volume_annotations(
        ec2_client, "throughput", vol_details["vol_type"], vol_id, vol_details["vol_size"]
    )
    iops_annotations = get_volume_annotations(
        ec2_client, "iops", vol_details["vol_type"], vol_id, vol_details["vol_size"]
    )

    widgets = [
        {
            "type": "text",
            "height": VOL_TEXT_HEADER_HEIGHT,
            "width": WIDGET_FULL_WIDTH,
            "y": y_start,
            "x": 0,
            "properties": {
                "markdown": f"### Volume: {vol_id} | Type: {vol_details['vol_type']}",
                "background": "transparent",
            },
        },
        {
            "type": "metric",
            "width": WIDGET_HALF_WIDTH,
            "height": WIDGET_GRAPH_HEIGHT,
            "x": 0,
            "y": y_start + VOL_TEXT_HEADER_HEIGHT,
            "properties": {
                "view": "timeSeries",
                "stacked": False,
                "metrics": [
                    [
                        {
                            "expression": f"IF(({period} - {metrics_numbrs['VolumeIdleTime']}) > 0, ({metrics_numbrs['VolumeReadOps']} + {metrics_numbrs['VolumeWriteOps']}) / CEIL({period} - {metrics_numbrs['VolumeIdleTime']}), 0)",
                            "label": "Estimated Average IOPS",
                            "id": exprs["avg_iops"],
                            "visible": True,
                        }
                    ],
                    [
                        "AWS/EBS",
                        "VolumeIdleTime",
                        "VolumeId",
                        vol_id,
                        {"id": metrics_numbrs["VolumeIdleTime"], "visible": False},
                    ],
                    [
                        "AWS/EBS",
                        "VolumeReadOps",
                        "VolumeId",
                        vol_id,
                        {"id": metrics_numbrs["VolumeReadOps"], "visible": False},
                    ],
                    [
                        "AWS/EBS",
                        "VolumeWriteOps",
                        "VolumeId",
                        vol_id,
                        {"id": metrics_numbrs["VolumeWriteOps"], "visible": False},
                    ],
                    [
                        "AWS/EBS",
                        "BurstBalance",
                        "VolumeId",
                        vol_id,
                        {
                            "id": metrics_numbrs["BurstBalance"],
                            "visible": is_burstable,
                            "color": "#000000",
                            "yAxis": "right",
                            "stat": "Average",
                        },
                    ],
                ],
                "region": region,
                "period": period,
                "stat": "Sum",
                "title": f"Estimated Average IOPS - {vol_id}",
                "start": start_time.strftime("%Y-%m-%dT%H:%M:%SZ"),
                "end": end_time.strftime("%Y-%m-%dT%H:%M:%SZ"),
                "annotations": iops_annotations,
                "yAxis": {"left": {"label": "IOPS", "showUnits": False}},
            },
        },
        {
            "type": "metric",
            "width": WIDGET_HALF_WIDTH,
            "height": WIDGET_GRAPH_HEIGHT,
            "x": WIDGET_HALF_WIDTH,
            "y": y_start + VOL_TEXT_HEADER_HEIGHT,
            "properties": {
                "view": "timeSeries",
                "stacked": False,
                "metrics": [
                    [
                        {
                            "expression": f"IF(({period} - {metrics_numbrs['VolumeIdleTime']}) > 0, (({metrics_numbrs['VolumeReadBytes']} + {metrics_numbrs['VolumeWriteBytes']}) / CEIL({period} - {metrics_numbrs['VolumeIdleTime']})) / 1024 / 1024, 0)",
                            "label": "Estimated Average Throughput",
                            "id": exprs["avg_throughput"],
                            "visible": True,
                        }
                    ],
                    [
                        "AWS/EBS",
                        "VolumeIdleTime",
                        "VolumeId",
                        vol_id,
                        {"id": metrics_numbrs["VolumeIdleTime"], "visible": False},
                    ],
                    [
                        "AWS/EBS",
                        "VolumeReadBytes",
                        "VolumeId",
                        vol_id,
                        {"id": metrics_numbrs["VolumeReadBytes"], "visible": False},
                    ],
                    [
                        "AWS/EBS",
                        "VolumeWriteBytes",
                        "VolumeId",
                        vol_id,
                        {"id": metrics_numbrs["VolumeWriteBytes"], "visible": False},
                    ],
                    [
                        "AWS/EBS",
                        "BurstBalance",
                        "VolumeId",
                        vol_id,
                        {
                            "id": metrics_numbrs["BurstBalance"],
                            "visible": is_burstable,
                            "color": "#000000",
                            "yAxis": "right",
                            "stat": "Average",
                        },
                    ],
                ],
                "region": region,
                "period": period,
                "stat": "Sum",
