                "width": WIDGET_HALF_WIDTH,
                "height": WIDGET_EXCEEDED_HEIGHT,
                "x": 0,
                "y": exceeded_y,
                "properties": {
                    "view": "timeSeries",
                    "stacked": False,
                    "metrics": [
                        [
                            "AWS/EBS",
                            "VolumeIOPSExceededCheck",
                            "VolumeId",
                            vol_id,
                            "InstanceId",
                            instance_id,
                            {"stat": "Sum"},
                        ],
                    ],
                    "region": region,
                    "period": period,
                    "title": f"VolumeIOPSExceededCheck - {vol_id}",
                    "start": start_time.strftime("%Y-%m-%dT%H:%M:%SZ"),
                    "end": end_time.strftime("%Y-%m-%dT%H:%M:%SZ"),
                    "yAxis": {"left": {"label": "", "showUnits": False, "min": 0}},
                    "annotations": {
                        "horizontal": [
                            {"label": "IOPS Exceeded", "value": 1, "color": "#d13212"},
                        ]
                    },
                },
            }
        )
        widgets.append(
            {
                "type": "metric",
                "width": WIDGET_HALF_WIDTH,
                "height": WIDGET_EXCEEDED_HEIGHT,
                "x": WIDGET_HALF_WIDTH,
                "y": exceeded_y,
                "properties": {
                    "view": "timeSeries",
                    "stacked": False,
                    "metrics": [
                        [
                            "AWS/EBS",
                            "VolumeThroughputExceededCheck",
                            "VolumeId",
                            vol_id,
                            "InstanceId",
                            instance_id,
                            {"stat": "Sum"},
                        ],
                    ],
                    "region": region,
                    "period": period,
                    "title": f"VolumeThroughputExceededCheck - {vol_id}",
                    "start": start_time.strftime("%Y-%m-%dT%H:%M:%SZ"),
                    "end": end_time.strftime("%Y-%m-%dT%H:%M:%SZ"),
                    "yAxis": {"left": {"label": "", "showUnits": False, "min": 0}},
                    "annotations": {
                        "horizontal": [
                            {"label": "Throughput Exceeded", "value": 1, "color": "#d13212"},
                        ]
                    },
                },
            }
        )
        next_y = exceeded_y + WIDGET_EXCEEDED_HEIGHT

    return widgets, next_y


# create ec2 related widget
def create_instance_widget(
    ec2_client,
    region,
    instance_id,
    vol_ids,
    ec2_info,
    period,
    start_time,
    end_time,
    is_nitro=False,
    instance_type_info=None,
    y_start=8,
):
    group_size = INSTANCE_WIDGET_GROUP_SIZE
    widgets = []
    iops_annotation = get_ec2_annotations(ec2_client, "iops", ec2_info, instance_type_info)
    throughput_annotations = get_ec2_annotations(ec2_client, "throughput", ec2_info, instance_type_info)

    # Process volumes in groups
    for group_index, group_start in enumerate(range(0, len(vol_ids), group_size)):
        group_vol_ids = vol_ids[group_start : group_start + group_size]
        volumes_string = ", ".join(group_vol_ids)  # Create string of volume IDs

        vol_iops_metrics = []
        vol_throughput_metrics = []

        # Process metrics for this group of volumes
        for i, vol_id in enumerate(group_vol_ids):
            # Calculate metric IDs based on group
            base_metric_id = (group_index * group_size * 6) + (i * 6)

            # IOPS metrics for this volume
            vol_iops_metrics.extend(
                [
                    [
                        "AWS/EBS",
                        "VolumeIdleTime",
                        "VolumeId",
                        vol_id,
                        {"id": f"m{base_metric_id + 1}", "visible": False},
                    ],
                    [
                        "AWS/EBS",
                        "VolumeReadOps",
                        "VolumeId",
                        vol_id,
                        {"id": f"m{base_metric_id + 2}", "visible": False},
                    ],
                    [
                        "AWS/EBS",
                        "VolumeWriteOps",
                        "VolumeId",
                        vol_id,
                        {"id": f"m{base_metric_id + 3}", "visible": False},
                    ],
                ]
            )

            # Throughput metrics for this volume
            vol_throughput_metrics.extend(
                [
                    [
                        "AWS/EBS",
                        "VolumeIdleTime",
                        "VolumeId",
                        vol_id,
                        {"id": f"m{base_metric_id + 1}", "visible": False},
                    ],
                    [
                        "AWS/EBS",
                        "VolumeReadBytes",
                        "VolumeId",
                        vol_id,
                        {"id": f"m{base_metric_id + 4}", "visible": False},
                    ],
                    [
                        "AWS/EBS",
                        "VolumeWriteBytes",
                        "VolumeId",
                        vol_id,
                        {"id": f"m{base_metric_id + 5}", "visible": False},
                    ],
                ]
            )

        # Create per-volume IOPS expressions using VolumeIdleTime, then sum them
        iops_per_vol = []
        for i in range(len(group_vol_ids)):
            base = (group_index * group_size * 6) + (i * 6)
            idle = f"m{base + 1}"
            read_ops = f"m{base + 2}"
            write_ops = f"m{base + 3}"
            iops_per_vol.append(f"IF(({period} - {idle}) > 0, ({read_ops} + {write_ops}) / CEIL({period} - {idle}), 0)")
        iops_expression = " + ".join(iops_per_vol)

        # Create per-volume Throughput expressions using VolumeIdleTime, then sum them
        throughput_per_vol = []
        for i in range(len(group_vol_ids)):
            base = (group_index * group_size * 6) + (i * 6)
            idle = f"m{base + 1}"
            read_bytes = f"m{base + 4}"
            write_bytes = f"m{base + 5}"
            throughput_per_vol.append(
                f"IF(({period} - {idle}) > 0, ({read_bytes} + {write_bytes}) / CEIL({period} - {idle}), 0)"
            )
        throughput_expression = f"({' + '.join(throughput_per_vol)}) / 1024 / 1024"

        # Create widgets for this group
        group_widgets = [
            {
                "type": "metric",
                "width": WIDGET_HALF_WIDTH,
                "height": WIDGET_GRAPH_HEIGHT,
                "x": 0,
                "y": y_start + (group_index * WIDGET_GRAPH_HEIGHT),
                "properties": {
                    "view": "timeSeries",
                    "stacked": False,
                    "metrics": [
                        [
                            {
                                "expression": iops_expression,
                                "label": f"{instance_id} - Group {group_index + 1} Estimated Average IOPS",
                                "id": f"e{group_index * 2 + 1}",
                                "visible": True,
                            }
                        ],
                        *vol_iops_metrics,
                    ],
                    "region": region,
                    "period": period,
                    "stat": "Sum",
                    "title": f"Estimated Average Total IOPS - Group {group_index + 1} (Volumes: {volumes_string})",
                    "start": start_time.strftime("%Y-%m-%dT%H:%M:%SZ"),
                    "end": end_time.strftime("%Y-%m-%dT%H:%M:%SZ"),
                    "annotations": iops_annotation,
                    "yAxis": {"left": {"label": "IOPS", "showUnits": False}},
                },
            },
            {
                "type": "metric",
                "width": WIDGET_HALF_WIDTH,
                "height": WIDGET_GRAPH_HEIGHT,
                "x": WIDGET_HALF_WIDTH,
                "y": y_start + (group_index * WIDGET_GRAPH_HEIGHT),
                "properties": {
                    "view": "timeSeries",
                    "stacked": False,
                    "metrics": [
                        [
                            {
                                "expression": throughput_expression,
                                "label": f"{instance_id} - Group {group_index + 1} Estimated Average Throughput",
                                "id": f"e{group_index * 2 + 2}",
                                "visible": True,
                            }
                        ],
                        *vol_throughput_metrics,
                    ],
                    "region": region,
                    "period": period,
                    "stat": "Sum",
                    "title": f"Estimated Average Total Throughput - Group {group_index + 1} (Volumes: {volumes_string})",
                    "start": start_time.strftime("%Y-%m-%dT%H:%M:%SZ"),
                    "end": end_time.strftime("%Y-%m-%dT%H:%M:%SZ"),
                    "annotations": throughput_annotations,
                    "yAxis": {"left": {"label": "MB/s", "showUnits": False}},
                },
            },
        ]
        widgets.extend(group_widgets)

        # Add EBS balance metrics if needed
        if ec2_info["ebs_optimized"] and group_index == 0:  # Only add once
            if (
                iops_annotation["horizontal"][0]["label"] == "Baseline IOPS"
                or throughput_annotations["horizontal"][0]["label"] == "Baseline Throughput (MB/s)"
            ):
                widgets[0]["properties"]["metrics"].append(
                    [
                        "AWS/EC2",
                        "EBSIOBalance%",
                        "InstanceId",
                        instance_id,
                        {
                            "id": "n1",
                            "region": region,
                            "yAxis": "right",
                            "stat": "Average",
                            "label": f"{instance_id} - EBSIOBalance%",
                        },
                    ]
                )
                widgets[1]["properties"]["metrics"].append(
                    [
                        "AWS/EC2",
                        "EBSByteBalance%",
                        "InstanceId",
                        instance_id,
                        {
                            "id": "n2",
                            "region": region,
                            "yAxis": "right",
                            "stat": "Average",
                            "label": f"{instance_id} - EBSByteBalance%",
                        },
                    ]
                )

    # Add InstanceEBSIOPSExceededCheck and InstanceEBSThroughputExceededCheck for Nitro instances
    if is_nitro:
        exceeded_y = y_start + (len(range(0, len(vol_ids), group_size)) * WIDGET_GRAPH_HEIGHT)
        widgets.append(
            {
                "type": "metric",
                "width": WIDGET_HALF_WIDTH,
                "height": WIDGET_EXCEEDED_HEIGHT,
                "x": 0,
                "y": exceeded_y,
                "properties": {
                    "view": "timeSeries",
                    "stacked": False,
                    "metrics": [
                        [
                            "AWS/EC2",
                            "InstanceEBSIOPSExceededCheck",
                            "InstanceId",
                            instance_id,
                            {"stat": "Sum"},
                        ],
                    ],
                    "region": region,
                    "period": period,
                    "title": f"InstanceEBSIOPSExceededCheck - {instance_id}",
                    "start": start_time.strftime("%Y-%m-%dT%H:%M:%SZ"),
                    "end": end_time.strftime("%Y-%m-%dT%H:%M:%SZ"),
                    "yAxis": {"left": {"label": "", "showUnits": False, "min": 0}},
                    "annotations": {
                        "horizontal": [
                            {"label": "IOPS Exceeded", "value": 1, "color": "#d13212"},
                        ]
                    },
                },
            }
        )
        widgets.append(
            {
                "type": "metric",
                "width": WIDGET_HALF_WIDTH,
                "height": WIDGET_EXCEEDED_HEIGHT,
                "x": WIDGET_HALF_WIDTH,
                "y": exceeded_y,
                "properties": {
                    "view": "timeSeries",
                    "stacked": False,
                    "metrics": [
                        [
                            "AWS/EC2",
                            "InstanceEBSThroughputExceededCheck",
                            "InstanceId",
                            instance_id,
                            {"stat": "Sum"},
                        ],
                    ],
                    "region": region,
                    "period": period,
                    "title": f"InstanceEBSThroughputExceededCheck - {instance_id}",
                    "start": start_time.strftime("%Y-%m-%dT%H:%M:%SZ"),
                    "end": end_time.strftime("%Y-%m-%dT%H:%M:%SZ"),
                    "yAxis": {"left": {"label": "", "showUnits": False, "min": 0}},
                    "annotations": {
                        "horizontal": [
                            {"label": "Throughput Exceeded", "value": 1, "color": "#d13212"},
                        ]
                    },
                },
            }
        )

    return widgets


def create_volume_dashboard(
    region,
    vol_ids,
    period,
    start_time,
    end_time,
    dashboard_name,
    ec2_client,
    y_no=5,
    exceeded_check_vol_ids=None,
    instance_id="",
    all_vol_details=None,
):
    if exceeded_check_vol_ids is None:
        exceeded_check_vol_ids = []

    if all_vol_details is None:
        all_vol_details = get_all_volume_details(vol_ids, ec2_client)

    # When a volume ID is the input, determine Nitro status and ExceededCheck eligibility
    if not exceeded_check_vol_ids and not instance_id:
        for vol_id, vol_info in all_vol_details.items():
            if vol_info["attachments"] and is_volume_exceeded_check_eligible(vol_info):
                attachments = vol_info.get("attachments", [])
                if not attachments:
                    continue
                # Multi-Attach volumes are already filtered out by is_volume_exceeded_check_eligible(),
                # so non-Multi-Attach volumes will have at most one attachment entry.
                attached_inst_id = attachments[0]["InstanceId"]
                try:
                    inst_response = ec2_client.describe_instances(InstanceIds=[attached_inst_id])
                except ClientError as error:
                    raise RuntimeError(
                        f"[ERROR] An error occurred when trying to retrieve instance information "
                        f"for volume {vol_id} - {str(error)}"
                    ) from None
                reservations = inst_response.get("Reservations", [])
                if not reservations or not reservations[0].get("Instances"):
                    continue
                inst_type = reservations[0]["Instances"][0].get("InstanceType")
                if not inst_type:
                    continue
                if is_nitro_instance(inst_type, ec2_client):
                    exceeded_check_vol_ids.append(vol_id)
                    instance_id = attached_inst_id

    # Build volume description notes
    vol_notes_items = [
        "If `Estimated Average IOPS` / `Estimated Average Throughput` is more than "
        "`Maximum IOPS` / `Maximum Throughput`, then microbursting is happening for that particular volume. "
        "Realtime analysis for microbursting may vary, to confirm further you can use an OS-level tool "
        "that has a finer granularity than CloudWatch.",
        "The maximum performance for certain volume types can only be achieved if "
        "`BurstBalance%` is greater than zero.",
        "For non-magnetic and non-Multi-Attach volumes attached to Nitro-based instances, "
        "`VolumeIOPSExceededCheck` / `VolumeThroughputExceededCheck` metrics are included in the dashboard. "
        "These metrics report whether an application consistently attempted to drive IOPS or throughput "
        "that exceeds the volume's provisioned performance within the last minute.",
        "For `standard` (magnetic) volumes, the displayed maximum limits (200 IOPS, 90 MB/s) are "
        "approximate upper bounds. Actual performance varies and is not guaranteed. "
        "Consider migrating to a current generation volume type (gp3) for consistent performance.",
        "For more information, please review - "
        "[How can I identify if my Amazon EBS volume is micro-bursting and then prevent this from happening?]"
        "(https://repost.aws/knowledge-center/ebs-identify-micro-bursting)",
    ]
    vol_notes_text = "\n".join(f"- {item}" for item in vol_notes_items)

    widgets = [
        {
            "type": "text",
            "height": VOL_DESC_HEIGHT,
            "width": WIDGET_FULL_WIDTH,
            "y": y_no,
            "x": 0,
            "properties": {
                "markdown": (
                    "### EBS Volume(s) Metrics\n\n"
                    "| Calculated Metric | Mathematical Expression | Unit |\n"
                    "| -------- | ------------------------- | ------ |\n"
                    "| Estimated Average IOPS | (SUM(VolumeReadOps) + SUM(VolumeWriteOps)) "
                    "/ CEIL(Period - SUM(VolumeIdleTime)) | IOPS |\n"
                    "| Estimated Average Throughput | (SUM(VolumeReadBytes) + SUM(VolumeWriteBytes)) "
                    "/ CEIL(Period - SUM(VolumeIdleTime)) / 1024 / 1024 | MiB/s |\n\n"
                    f"**Notes:**\n{vol_notes_text}"
                )
            },
        }
    ]

    current_y = y_no + VOL_DESC_HEIGHT  # After description text widget
    for i, vol_id in enumerate(vol_ids):
        vol_details = all_vol_details[vol_id]
        vol_widgets, current_y = create_volume_widget(
            region,
            vol_id,
            vol_details,
            period,
            start_time,
            end_time,
            ec2_client,
            i,
            current_y,
            exceeded_check=(vol_id in exceeded_check_vol_ids),
            instance_id=instance_id,
        )
        widgets.extend(vol_widgets)

    # footer widget - placed at the bottom after all volume widgets
    footer_widget = {
        "type": "text",
        "height": WIDGET_FOOTER_HEIGHT,
        "width": WIDGET_FULL_WIDTH,
        "y": current_y,
        "x": 0,
        "properties": {
            "markdown": f"**In order to delete the dashboard, run the CLI command** \n\n ```\n $ aws cloudwatch delete-dashboards --dashboard-names {dashboard_name} --region {region}\n ``` \n\n **Note:** You will need `cloudwatch:DeleteDashboards` IAM permission to delete the dashboard."
        },
    }

    widgets.append(footer_widget)

    return widgets


def create_instance_dashboard(region, instance_id, vol_ids, period, start_time, end_time, dashboard_name, ec2_client):
    ec2_info = get_ec2_info(instance_id, ec2_client)

    try:
        instance_type_info = ec2_client.describe_instance_types(
            InstanceTypes=[ec2_info["instance_class"]],
        )
    except ClientError as error:
        raise RuntimeError(
            f"[ERROR] An error occurred when trying to describe the instance type {ec2_info['instance_class']} - {str(error)}"
        ) from None

    nitro = is_nitro_from_instance_type_info(instance_type_info)

    all_vol_details = get_all_volume_details(vol_ids, ec2_client)
    exceeded_check_vol_ids = []
    if nitro:
        for vol_id, vol_info in all_vol_details.items():
            if is_volume_exceeded_check_eligible(vol_info):
                exceeded_check_vol_ids.append(vol_id)

    nitro_info = f"\n- Nitro Instance: {nitro}"
    notes_items = [
        "The maximum performance can only be achieved if `BurstBalance%` for EBS volume "
        "or `EBSIOBalance%`, `EBSByteBalance%` for instance is greater than zero.",
        "For Nitro-based instances, `ExceededCheck` metrics are included in the dashboard. "
        "These metrics report whether an application attempted to drive IOPS or throughput "
        "that exceeds the maximum EBS limits for the instance or volume within the last minute.",
    ]
    notes_text = "\n\n**Notes:**\n" + "\n".join(f"- {item}" for item in notes_items)

    widgets = [
        {
            "type": "text",
            "height": INSTANCE_DESC_HEIGHT,
            "width": WIDGET_FULL_WIDTH,
            "y": 0,
            "x": 0,
            "properties": {
                "markdown": f"# Aggregated Metrics for EC2 Instance {instance_id}\n- Instance Type: {ec2_info['instance_class']}\n- EBS Optimized: {ec2_info['ebs_optimized']}{nitro_info} \n\n\n[button: More details on EBS Optimized instances](https://docs.aws.amazon.com/AWSEC2/latest/UserGuide/ebs-optimized.html)\n[button:More details on EBS Volume Types](https://docs.aws.amazon.com/AWSEC2/latest/UserGuide/ebs-volume-types.html)\n\n[button: How do I use CloudWatch to view the aggregate Amazon EBS performance metrics for an EC2 instance?](https://repost.aws/knowledge-center/ebs-aggregate-cloudwatch-performance)\n\n| Calculated Metric | Mathematical Expression | Unit |\n| -------- | ------------------------- | ------ |\n| Estimated Average Total IOPS | SUM(For All Volumes[(SUM(VolumeReadOps) + SUM(VolumeWriteOps)) / CEIL(Period - VolumeIdleTime)]) | IOPS |\n| Estimated Average Total Throughput | SUM(For All Volumes[(SUM(VolumeReadBytes) + SUM(VolumeWriteBytes)) / CEIL(Period - VolumeIdleTime)]) / 1024 / 1024 | MiB/s |{notes_text}"
            },
        }
    ]

    ec2_widget = create_instance_widget(
        ec2_client,
        region,
        instance_id,
        vol_ids,
        ec2_info,
        period,
        start_time,
        end_time,
        is_nitro=nitro,
        instance_type_info=instance_type_info,
        y_start=INSTANCE_DESC_HEIGHT,
    )
    widgets.extend(ec2_widget)

    # Calculate volume dashboard start position based on instance widgets
    num_groups = len(range(0, len(vol_ids), INSTANCE_WIDGET_GROUP_SIZE))
    volume_y_start = INSTANCE_DESC_HEIGHT + (num_groups * WIDGET_GRAPH_HEIGHT)
    if nitro:
        volume_y_start += WIDGET_EXCEEDED_HEIGHT

    volume_widgets = create_volume_dashboard(
        region,
        vol_ids,
        period,
        start_time,
        end_time,
        dashboard_name,
        ec2_client,
        volume_y_start,
        exceeded_check_vol_ids=exceeded_check_vol_ids,
        instance_id=instance_id,
        all_vol_details=all_vol_details,
    )
    widgets.extend(volume_widgets)

    return widgets


def create_dashboard(events, context):
    # variables from events/context
    region = context["global:REGION"]
    partition = context["global:AWS_PARTITION"]
    execution_id = context["automation:EXECUTION_ID"]
    start_time = datetime.datetime.strptime(events.get("start_time"), "%Y-%m-%dT%H:%M:%S")
    end_time = datetime.datetime.strptime(events.get("end_time"), "%Y-%m-%dT%H:%M:%S")
    resource_id = events.get("resource_id")

    # ec2 client
    ec2_client = boto3.client("ec2", region_name=region)
    cw_client = boto3.client("cloudwatch", region_name=region)

    # calculate period
    period = get_period_value(start_time)

    dashboard_name = f"AWSSupport-{resource_id}-EBS-Performance-{execution_id}"

    if resource_id.startswith("vol-"):
        widgets = create_volume_dashboard(
            region, [resource_id], period, start_time, end_time, dashboard_name, ec2_client
        )

    elif resource_id.startswith("i-"):
        vol_ids = get_attached_volumes(resource_id, ec2_client)
        widgets = create_instance_dashboard(
            region, resource_id, vol_ids, period, start_time, end_time, dashboard_name, ec2_client
        )
    else:
        raise ValueError(f"[ERROR] The resource ID is not a valid EBS volume or EC2 instance: {resource_id}")

    dashboard = {
        "start": start_time.strftime("%Y-%m-%dT%H:%M:%S"),
        "end": end_time.strftime("%Y-%m-%dT%H:%M:%S"),
        "periodOverride": "inherit",
        "widgets": widgets,
    }

    try:
        cw_client.put_dashboard(DashboardName=dashboard_name, DashboardBody=json.dumps(dashboard))
        domain_url_mapping = {
            "aws": "aws.amazon.com",
            "aws-cn": "amazonaws.cn",
            "aws-us-gov": "amazonaws-us-gov.com",
            "aws-iso": "c2shome.ic.gov",
            "aws-iso-b": "sc2shome.sgov.gov",
            "aws-iso-e": "csphome.adc-e.uk",
            "aws-iso-f": "csphome.hci.ic.gov",
        }
        domain_url = domain_url_mapping[partition]
        cw_dashboard_url = (
            f"https://console.{domain_url}/cloudwatch/home?region={region}#dashboards:name={dashboard_name}"
        )
        message = f"Open the CloudWatch Dashboard URL in your browser to see the performance metrics for the target resource '{resource_id}'.\nYou can delete the CloudWatch Dashboard from the CloudWatch console.\n"
        return {"message": message, "url": cw_dashboard_url}

    except ClientError as error:
        raise RuntimeError(
            f"[ERROR] An error occurred when trying to create the CloudWatch dashboard - {str(error)}"
        ) from None
